2. жҢӮиҪҪзӮ№й…ҚзҪ®дҝЎжҒҜ, еӮЁеӯҳдәҺжҢӮиҪҪзӮ№и·Ҝеҫ„дёӢзҡ„`mountable.json`дёӯ, й…ҚзҪ®еҶ…зҡ„ж–Үд»¶и·Ҝеҫ„дёәMCжңҚеҠЎеҷЁзӣ®еҪ•зҡ„зӣёеҜ№и·Ҝеҫ„
```json5
{
  // жҳҜеҗҰйҖҡиҝҮдәҶдәәе·ҘзЎ®и®Ө
  "checked": false,
  // жҸҸиҝ°дҝЎжҒҜ
  "desc":  "Demo server",
  // жӯӨжҢӮиҪҪзӮ№еҗҜеҠЁе‘Ҫд»Ө
