  // еҚ з”ЁжӯӨжҢӮиҪҪзӮ№зҡ„MCDRе®һдҫӢзҡ„жҢӮиҪҪж ҮиҜҶ, з©әд»ЈиЎЁжңӘжҢӮиҪҪ
  "occupied_by": "",
  // жӯӨжҢӮиҪҪзӮ№зҡ„йҮҚзҪ®и·Ҝеҫ„, з©әжҲ–иҖ….д»ЈиЎЁж— йҮҚзҪ®и·Ҝеҫ„
  "reset_path": "",
  // жӯӨжҢӮиҪҪзӮ№зҡ„йҮҚзҪ®ж–№жі•, fullд»ЈиЎЁе…ЁйғЁйҮҚзҪ®, regionд»ЈиЎЁдҝқз•ҷзҺ©е®¶дҝЎжҒҜ(еҰӮи·‘й…·и®°еҪ•)
  "reset_type": "full",
  // дё“дёәжӯӨжҢӮиҪҪзӮ№зҡ„mcdrжҸ’д»¶зӣ®еҪ•, дҪҝеҫ—жҜҸдёӘжҢӮиҪҪзӮ№еҸҜдҪҝз”Ёдё“жңүзҡ„жҸ’д»¶, з©әжҲ–иҖ….д»ЈиЎЁж— 
  "plugin_dir": "",
  "stats": {
    // жӯӨжҢӮиҪҪзӮ№зҡ„з»ҹи®ЎдҝЎжҒҜ, е°ҶиҮӘеҠЁз”ҹжҲҗ
  }
